function loadPreviousReports() {
    var origin = window.location.origin;   // e.g. "https://demo.envisionscada.com"
    var reports = [];

    // Loop last 10 days
    for (var i = 1; i <= 10; i++) {
        var day = moment().subtract(i, 'days').format('YYYY-MM-DD');
        var url = origin + '/Reports/Daily Report ' + day + '.pdf';
        reports.push(url);
    }

    // Store array into client variable (comma-separated string)
    PageWriteVariable('client.previousreports', reports.join(';'));
}

